from flask import Blueprint, request, jsonify
from models import User
from db import db

routes_blueprint = Blueprint('routes', __name__)

@routes_blueprint.route('/users', methods=['POST'])
def create_user():
	firstname = request.json['firstname']
	lastname = request.json['lastname']
	user = User(firstname=firstname, lastname=lastname)
	db.session.add(user)
	db.session.commit()
	return jsonify({'firstname': user.firstname, 'lastname': user.lastname}), 201


@routes_blueprint.route('/users/<firstname>', methods=['GET'])
def get_user_by_name(firstname):
	user = User.query.filter_by(firstname=firstname).first()
	if user:
		return jsonify({'firstname': user.firstname, 'lastname': user.lastname}), 200
	else:
		return jsonify({'error': 'User not found'}), 404


@routes_blueprint.route('/db/drop/users', methods=['POST'])
def drop_user_table():
	User.__table__.drop(db.engine)
	return jsonify({'message': 'User table dropped!'}), 200

